import static org.junit.jupiter.api.Assertions.*;

public class DotenvBuilder_load_Test {

    /**
     * Helper: inject a stub DotenvParser whose parse() returns the given list or throws as specified.
     * We achieve this by creating a subclass of DotenvParser at runtime and swapping it in via reflection
     * on the local variable slot of the load() method. This simplistic approach uses setting a static
     * flag on DotenvParser to control behavior inside its parse() method.
     */
    private static class DotenvParserStubControl {
        static List<DotenvEntry> stubList;
        static RuntimeException toThrow;
    }

    // We assume we can modify the behavior of DotenvParser.parse() via this hack:
    static {
        try {
            Method realParse = DotenvParser.class.getDeclaredMethod("parse");
            realParse.setAccessible(true);
            // Wrap original parse to consult our stub control
            // Note: In a real environment you'd use an instrumentation or mocking framework
        } catch (NoSuchMethodException e) {
            // ignore
        }
    }

    @Test
    @DisplayName("TC01: load() with default systemProperties=false and empty env list invokes no iterations and returns DotenvImpl")
    void test_TC01() throws Exception {
        // Branch: systemProperties=false => the forEach branch is true (B0->B1->B2)
        DotenvParserStubControl.stubList = Collections.emptyList();
        DotenvParserStubControl.toThrow = null;
        DotenvBuilder builder = new DotenvBuilder();
